import json
import sys

if hasattr(sys, "set_int_max_str_digits"):
    sys.set_int_max_str_digits(0)


def fibonacci(n: int) -> int:
    normalized = max(0, int(n))
    previous = 0
    current = 1
    for _ in range(normalized):
        previous, current = current, previous + current
    return previous


payload = json.loads(sys.argv[1] if len(sys.argv) > 1 else '{"n": 0}')
print(fibonacci(payload.get("n", 0)))
